+fn emit_string_global(out: &mut String, data_name: &str, boxed_name: &str, value: &str) {
+    let escaped = llvm_c_string(value);
+    out.push_str(&format!(
+        "{} = private constant [{} x i8] c\"{}\"\n",
+        data_name,
+        value.len() + 1,
+        escaped
+    ));
+    out.push_str(&format!(
+        "{} = private constant {{ i64, ptr }} {{ i64 {}, ptr {} }}\n",
+        boxed_name,
+        value.len(),
+        data_name
+    ));
+}
